import React, { useState, useEffect } from 'react';
import { cities, recommendations, places } from '../utils/api';

const BudgetRecommendations = () => {
  const [cityList, setCityList] = useState([]);
  const [selectedCity, setSelectedCity] = useState('');
  const [budget, setBudget] = useState('');
  const [tripName, setTripName] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [generatedItinerary, setGeneratedItinerary] = useState([]);
  const [alternativePlaces, setAlternativePlaces] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showAlternatives, setShowAlternatives] = useState(false);
  const [editingId, setEditingId] = useState(null);

  useEffect(() => {
    fetchCities();
    loadEditingItinerary();
  }, []);

  const loadEditingItinerary = () => {
    const editing = JSON.parse(localStorage.getItem('editingItinerary') || 'null');
    if (editing) {
      setEditingId(editing.id);
      setTripName(editing.tripName);
      setSelectedCity(editing.city);
      setBudget(editing.budget);
      setStartDate(editing.startDate);
      setEndDate(editing.endDate);
      localStorage.removeItem('editingItinerary');
    }
  };

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const calculateDays = () => {
    if (!startDate || !endDate) return 0;
    const start = new Date(startDate);
    const end = new Date(endDate);
    const diffTime = Math.abs(end - start);
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
    return Math.min(diffDays, 6); // Max 6 days
  };

  const handleGenerateItinerary = async (e) => {
    e.preventDefault();
    if (!selectedCity || !budget || !tripName || !startDate || !endDate) return;

    const days = calculateDays();
    if (days > 6) {
      alert('Maximum trip duration is 6 days. Please select dates within 6 days.');
      return;
    }

    setLoading(true);
    try {
      const [recommendationsResponse, allPlacesResponse] = await Promise.all([
        recommendations.getBudgetRecommendations({
          city_id: selectedCity,
          budget: parseFloat(budget)
        }),
        places.getByCity(selectedCity)
      ]);

      const recommended = recommendationsResponse.data.recommendations || [];
      const organizedItinerary = organizeByDays(recommended, days, parseFloat(budget));

      setGeneratedItinerary(organizedItinerary);
      setAlternativePlaces(allPlacesResponse.data || []);

      // Auto-save to localStorage
      localStorage.setItem('itinerary', JSON.stringify(recommended));

    } catch (error) {
      console.error('Failed to generate itinerary:', error);
      alert('Failed to generate itinerary');
    } finally {
      setLoading(false);
    }
  };

  const organizeByDays = (places, numDays, budget) => {
    const days = Array(numDays).fill().map((_, i) => ({ day: i + 1, places: [] }));

    // Group places by type and sort by rating (best first)
    const hotels = places.filter(p => p.type === 'HOTEL').sort((a, b) => b.rating - a.rating);
    const restaurants = places.filter(p => p.type === 'RESTAURANT').sort((a, b) => b.rating - a.rating);
    const attractions = places.filter(p => p.type === 'ATTRACTION').sort((a, b) => b.rating - a.rating);

    let remainingBudget = budget;
    const selectedPlaces = [];

    // Select places within budget using round-robin to ensure balanced days
    const allPlacesByType = [hotels, restaurants, attractions];

    for (let round = 0; round < Math.max(hotels.length, restaurants.length, attractions.length); round++) {
      for (let typeIndex = 0; typeIndex < 3; typeIndex++) {
        const placesOfType = allPlacesByType[typeIndex];
        if (placesOfType[round] && remainingBudget >= placesOfType[round].price) {
          selectedPlaces.push(placesOfType[round]);
          remainingBudget -= placesOfType[round].price;
        }
      }
    }

    // Distribute selected places across days using round-robin
    selectedPlaces.forEach((place, index) => {
      const dayIndex = index % numDays;
      days[dayIndex].places.push(place);
    });

    return days;
  };

  const replacePlace = (dayIndex, oldPlace, newPlace) => {
    const updated = generatedItinerary.map((day, index) => {
      if (index === dayIndex) {
        return {
          ...day,
          places: day.places.map(place => 
            place.id === oldPlace.id ? newPlace : place
          )
        };
      }
      return day;
    });
    setGeneratedItinerary(updated);

    // Update localStorage with flat array
    const flatPlaces = updated.flatMap(day => day.places);
    localStorage.setItem('itinerary', JSON.stringify(flatPlaces));
  };

  const removePlace = (dayIndex, placeId) => {
    const updated = generatedItinerary.map((day, index) => {
      if (index === dayIndex) {
        return {
          ...day,
          places: day.places.filter(place => place.id !== placeId)
        };
      }
      return day;
    });
    setGeneratedItinerary(updated);

    // Update localStorage with flat array
    const flatPlaces = updated.flatMap(day => day.places);
    localStorage.setItem('itinerary', JSON.stringify(flatPlaces));
  };

  const getTotalCost = () => {
    return generatedItinerary.flatMap(day => day.places).reduce((total, place) => total + parseFloat(place.price), 0);
  };

  const getAlternativesByType = (type) => {
    const allPlaces = generatedItinerary.flatMap(day => day.places);
    return alternativePlaces.filter(place => 
      place.type === type && !allPlaces.find(p => p.id === place.id)
    );
  };

  const saveItinerary = () => {
    const flatPlaces = generatedItinerary.flatMap(day => day.places);
    const newItinerary = {
      id: Date.now(),
      tripName,
      city: cityList.find(c => c.id == selectedCity)?.name,
      budget,
      startDate,
      endDate,
      days: calculateDays(),
      places: flatPlaces,
      totalCost: getTotalCost(),
      savedAt: new Date().toISOString()
    };

    const existingItineraries = JSON.parse(localStorage.getItem('savedItineraries') || '[]');
    existingItineraries.push(newItinerary);
    localStorage.setItem('savedItineraries', JSON.stringify(existingItineraries));

    alert('Itinerary saved successfully!');
    window.location.href = '/trips';
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Auto Itinerary Generator</h1>
        <p style={styles.subtitle}>Get an optimized itinerary generated automatically within your budget</p>
      </div>

      <div style={styles.formContainer}>
        <form onSubmit={handleGenerateItinerary} style={styles.form}>
          <div style={styles.formRow}>
            <div style={styles.formField}>
              <label style={styles.label}>Trip Name:</label>
              <input
                type="text"
                value={tripName}
                onChange={(e) => setTripName(e.target.value)}
                style={styles.input}
                placeholder="Enter trip name"
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Select City:</label>
              <select
                value={selectedCity}
                onChange={(e) => setSelectedCity(e.target.value)}
                style={styles.select}
                required
              >
                <option value="">Choose a city</option>
                {cityList.map(city => (
                  <option key={city.id} value={city.id}>{city.name}</option>
                ))}
              </select>
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Budget (NPR):</label>
              <input
                type="number"
                value={budget}
                onChange={(e) => setBudget(e.target.value)}
                style={styles.input}
                placeholder="Enter your budget"
                required
              />
            </div>
          </div>
          <div style={styles.formRow}>
            <div style={styles.formField}>
              <label style={styles.label}>Start Date:</label>
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>End Date:</label>
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                style={styles.input}
                min={startDate}
                required
              />
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Duration:</label>
              <input
                type="text"
                value={startDate && endDate ? `${calculateDays()} days` : ''}
                style={{...styles.input, backgroundColor: '#f3f4f6'}}
                readOnly
                placeholder="Auto-calculated"
              />
            </div>
          </div>
          <button type="submit" style={styles.submitButton} disabled={loading}>
            {loading ? 'Generating Itinerary...' : 'Generate Itinerary'}
          </button>
        </form>
      </div>

      {generatedItinerary.length > 0 && (
        <div style={styles.resultsContainer}>
          <div style={styles.resultsHeader}>
            <h2 style={styles.resultsTitle}>Your {calculateDays()}-Day Itinerary: {tripName}</h2>
            <div style={styles.headerActions}>
              <div style={styles.budgetInfo}>
                <span>Total: NPR {getTotalCost()}</span>
                <span style={{color: budget - getTotalCost() >= 0 ? '#059669' : '#ef4444'}}>
                  Remaining: NPR {Math.max(0, budget - getTotalCost()).toFixed(2)}
                </span>
              </div>
              <button onClick={saveItinerary} style={styles.saveButton}>
                Save Itinerary
              </button>
            </div>
          </div>

          {generatedItinerary.map((day, dayIndex) => (
            <div key={day.day} style={styles.dayContainer}>
              <h3 style={styles.dayTitle}>Day {day.day}</h3>
              <div style={styles.placesGrid}>
                {day.places.map(place => (
                  <div key={place.id} style={styles.placeCard}>
                    {place.image_url && (
                      <img 
                        src={`http://localhost:5000${place.image_url}`} 
                        alt={place.name}
                        style={styles.placeImage}
                      />
                    )}
                    <div style={styles.cardContent}>
                      <h3 style={styles.placeName}>{place.name}</h3>
                      <p style={styles.placeType}>{place.type}</p>
                      <p style={styles.price}>NPR {place.price}</p>
                      <p style={styles.rating}>★ {place.rating}</p>

                      <div style={styles.cardActions}>
                        <button 
                          onClick={() => setShowAlternatives(showAlternatives === `${dayIndex}-${place.id}` ? false : `${dayIndex}-${place.id}`)}
                          style={styles.changeButton}
                        >
                          Change
                        </button>
                        <button 
                          onClick={() => removePlace(dayIndex, place.id)}
                          style={styles.removeButton}
                        >
                          Remove
                        </button>
                      </div>

                      {showAlternatives === `${dayIndex}-${place.id}` && (
                        <div style={styles.alternatives}>
                          <h4>Alternatives:</h4>
                          {getAlternativesByType(place.type).slice(0, 3).map(alt => (
                            <div key={alt.id} style={styles.altPlace}>
                              <span>{alt.name} - NPR {alt.price}</span>
                              <button 
                                onClick={() => {
                                  replacePlace(dayIndex, place, alt);
                                  setShowAlternatives(false);
                                }}
                                style={styles.selectButton}
                              >
                                Select
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

